var n=Object.defineProperty,a=Object.defineProperties,s=Object.getOwnPropertyDescriptors,t=Object.getOwnPropertySymbols,e=Object.prototype.hasOwnProperty,o=Object.prototype.propertyIsEnumerable,p=(a,s,t)=>s in a?n(a,s,{enumerable:!0,configurable:!0,writable:!0,value:t}):a[s]=t;import{b as c,o as l,c as u,q as i,A as r,u as k,f as d,r as m,j as g,t as h,F as v,m as f,w,a as b}from"./app.71f27b91.js";const y={props:{modelValue:{required:!0,type:Object}},emits:["update:modelValue"],setup(n,{emit:m}){const g=n,h=c((()=>new Proxy(g.modelValue,{set(n,c,l){var u;return m("update:modelValue",(u=((n,a)=>{for(var s in a||(a={}))e.call(a,s)&&p(n,s,a[s]);if(t)for(var s of t(a))o.call(a,s)&&p(n,s,a[s]);return n})({},n),a(u,s({[c]:l})))),!0}})));return(n,a)=>(l(),u("form",null,[i(d("input",{"onUpdate:modelValue":a[0]||(a[0]=n=>k(h).firstName=n)},null,512),[[r,k(h).firstName]]),i(d("input",{"onUpdate:modelValue":a[1]||(a[1]=n=>k(h).lastName=n)},null,512),[[r,k(h).lastName]]),i(d("input",{"onUpdate:modelValue":a[2]||(a[2]=n=>k(h).city=n)},null,512),[[r,k(h).city]]),i(d("input",{"onUpdate:modelValue":a[3]||(a[3]=n=>k(h).country=n)},null,512),[[r,k(h).country]]),i(d("input",{"onUpdate:modelValue":a[4]||(a[4]=n=>k(h).email=n)},null,512),[[r,k(h).email]]),i(d("input",{"onUpdate:modelValue":a[5]||(a[5]=n=>k(h).phone=n)},null,512),[[r,k(h).phone]])]))}},V={setup(n){const a=m({firstName:"Adam",lastName:"Bell",city:"Copenhagen",country:"Denmark",email:"exp@s.com",phone:"N/A"});return(n,s)=>(l(),u(v,null,[g(y,{modelValue:a.value,"onUpdate:modelValue":s[0]||(s[0]=n=>a.value=n)},null,8,["modelValue"]),d("pre",null,"Bound value: "+h(a.value),1)],64))}},q=b('<h1 id="computed-with-v-model" tabindex="-1">Computed with v-model <a class="header-anchor" href="#computed-with-v-model" aria-hidden="true">#</a></h1><p>The principle of one-way data flow, with &#39;props down, events up&#39;, is just an extension of the idea that data should only be modified by its owner. This same idea can be extended to other scenarios, such as using Vuex, where the store is considered the owner of the data and so it should only be mutated by the store.</p><p>This causes problems when working with <code>v-model</code>, which attempts to modify the value directly. We can work around that using a <code>computed</code> value with a <code>get</code> and <code>set</code>.</p><p>There are more complete examples for <a href="./../components/checkbox.html">Checkbox</a> and <a href="./../components/radio.html">Radio</a> components, but to reduce it down to the essentials with an <code>&lt;input&gt;</code>:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>inputValue<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>With:</p><div class="language-js"><pre><code><span class="token keyword">const</span> inputValue <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token function">get</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">// return the current value</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token function">set</span> <span class="token punctuation">(</span>newValue<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">// Tell the data&#39;s owner to update the value</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>So for Vuex we might do something like this:</p><div class="language-js"><pre><code><span class="token keyword">const</span> inputValue <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token function-variable function">get</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> store<span class="token punctuation">.</span>state<span class="token punctuation">.</span>value<span class="token punctuation">,</span>\n  <span class="token function-variable function">set</span><span class="token operator">:</span> <span class="token parameter">newValue</span> <span class="token operator">=&gt;</span> store<span class="token punctuation">.</span><span class="token function">commit</span><span class="token punctuation">(</span><span class="token string">&#39;updateValue&#39;</span><span class="token punctuation">,</span> newValue<span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>A similar idea is common when working with data passed down from a parent component:</p><div class="language-js"><pre><code><span class="token keyword">const</span> inputValue <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token function-variable function">get</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> props<span class="token punctuation">.</span>value<span class="token punctuation">,</span>\n  <span class="token function-variable function">set</span><span class="token operator">:</span> <span class="token parameter">newValue</span> <span class="token operator">=&gt;</span> <span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;update:value&#39;</span><span class="token punctuation">,</span> newValue<span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>Using an event with a name of the form <code>update:propName</code> allows it to be used with <code>v-model</code> on the parent. The default prop name for this would be <code>modelValue</code>. As such, the technique described here is the standard way to &#39;pass on&#39; a <code>v-model</code> from a component&#39;s parent to one of its children.</p><h2 id="libraries" tabindex="-1">Libraries <a class="header-anchor" href="#libraries" aria-hidden="true">#</a></h2><p>This pattern is so common that it can be found in composable libraries:</p><ul><li><a href="https://vueuse.org/core/useVModel/" target="_blank" rel="noopener noreferrer">VueUse - useVModel</a></li><li><a href="https://pikax.me/vue-composable/composable/misc/vmodel.html" target="_blank" rel="noopener noreferrer">vue-composable - useVModel</a></li></ul><h2 id="alternatives" tabindex="-1">Alternatives <a class="header-anchor" href="#alternatives" aria-hidden="true">#</a></h2><p>It is possible to achieve something similar by avoiding the use of <code>v-model</code> on the child and splitting it up into a prop and event instead. e.g.:</p><div class="language-html"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">:value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>value<span class="token punctuation">&quot;</span></span> <span class="token attr-name">@input</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>$emit(<span class="token punctuation">&#39;</span>update:value<span class="token punctuation">&#39;</span>, $event.target.value)<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>This may be tempting, but it does move more logic into the template, which is usually regarded as a bad thing. It&#39;s also worth noting that using <code>v-model</code> on native elements, such as <code>&lt;input&gt;</code> and <code>&lt;select&gt;</code>, actually adds some extra functionality that you won&#39;t get if you implement your own event listeners. e.g.:</p><ul><li>For text inputs, <code>v-model</code> adds special handling for IME composition.</li><li>For radios, <code>v-model</code> supports the use of non-string values for the <code>value</code>. It also makes managing the <code>checked</code> option much simpler.</li><li>For checkboxes, <code>v-model</code> adds support for handling <code>true-value</code>, <code>false-value</code> and the use of a <code>value</code> in conjunction with arrays and sets. As with radios it makes managing the <code>checked</code> option much simpler for non-boolean cases.</li><li>For <code>&lt;select&gt;</code>, it gives similar benefits to either radios and checkboxes, depending on whether the <code>multiple</code> attribute is included.</li></ul><p>These potential problems don&#39;t apply when using <code>v-model</code> on components, so splitting it up into a prop/event pair is less fraught, but consistently sticking to using a <code>computed</code> comes with very little risk and tends to be easier to maintain.</p><h2 id="advanced-usage-proxying-objects" tabindex="-1">Advanced usage - proxying objects <a class="header-anchor" href="#advanced-usage-proxying-objects" aria-hidden="true">#</a></h2><p>A less common scenario involves passing a large object of field values to a form component:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>user-edit-form</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>user<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>pre</span><span class="token punctuation">&gt;</span></span>Bound value: {{ user }}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>pre</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> ref <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n<span class="token keyword">import</span> UserEditForm <span class="token keyword">from</span> <span class="token string">&#39;./user-edit-form.vue&#39;</span>\n\n<span class="token keyword">const</span> user <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  firstName<span class="token operator">:</span> <span class="token string">&#39;Adam&#39;</span><span class="token punctuation">,</span>\n  lastName<span class="token operator">:</span> <span class="token string">&#39;Bell&#39;</span><span class="token punctuation">,</span>\n  city<span class="token operator">:</span> <span class="token string">&#39;Copenhagen&#39;</span><span class="token punctuation">,</span>\n  country<span class="token operator">:</span> <span class="token string">&#39;Denmark&#39;</span><span class="token punctuation">,</span>\n  email<span class="token operator">:</span> <span class="token string">&#39;exp@s.com&#39;</span><span class="token punctuation">,</span>\n  phone<span class="token operator">:</span> <span class="token string">&#39;N/A&#39;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>Inside <code>user-edit-form</code> we want to provide inputs for each of these 6 properties. But having to write 6 separate <code>computed</code> values, one for each input, will quickly get annoying.</p><p>One trick to cut down on the boilerplate is to use a JS <code>Proxy</code> to do the sleight-of-hand for the reading and writing of properties instead of a <code>computed</code>. We&#39;ll still use a single <code>computed</code> to ensure everything stays reactive, but one is all we need:</p><div class="language-vue"><pre><code><span class="token comment">&lt;!-- user-edit-form.vue --&gt;</span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>form</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.firstName<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.lastName<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.city<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.country<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.email<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">v-model</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>model.phone<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>form</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">setup</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> computed <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span>\n\n<span class="token keyword">const</span> props <span class="token operator">=</span> <span class="token function">defineProps</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  modelValue<span class="token operator">:</span> <span class="token punctuation">{</span>\n    required<span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>\n    type<span class="token operator">:</span> Object\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> emit <span class="token operator">=</span> <span class="token function">defineEmits</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> model <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>props<span class="token punctuation">.</span>modelValue<span class="token punctuation">,</span> <span class="token punctuation">{</span>\n    <span class="token function">set</span> <span class="token punctuation">(</span>obj<span class="token punctuation">,</span> key<span class="token punctuation">,</span> value<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> <span class="token operator">...</span>obj<span class="token punctuation">,</span> <span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token operator">:</span> value <span class="token punctuation">}</span><span class="token punctuation">)</span>\n      <span class="token keyword">return</span> <span class="token boolean">true</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>Putting that all together gives:</p>',28),j=b('<p>While it might look a bit fiddly if you aren&#39;t used to working with a <code>Proxy</code>, most of this code is very reusable and can be hidden away behind a utility function. We could create a similar utility function for performing the same bit of trickery with an object coming from a Vuex store.</p><p>The approach does violate another best practice. The usual recommendation is to avoid mutating the properties of an object returned from a <code>computed</code>, as they&#39;re considered transient. However, we&#39;re breaking that rule knowingly here as mutating those properties is the whole point of the approach.</p><p>In theory, it is possible to extend this idea to work with nested objects, though it quickly gets unwieldy trying to make all the relevant copies. It&#39;s probably better to rethink your approach in that scenario.</p><p>Another possible extension is to combine this approach with the earlier strategy of using <code>computed</code> with <code>get</code> and <code>set</code>. This gives us something quite powerful, with the option to either replace individual properties or replace the whole object:</p><div class="language-js"><pre><code><span class="token keyword">const</span> model <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token function">get</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Proxy</span><span class="token punctuation">(</span>props<span class="token punctuation">.</span>modelValue<span class="token punctuation">,</span> <span class="token punctuation">{</span>\n      <span class="token function">set</span> <span class="token punctuation">(</span>obj<span class="token punctuation">,</span> key<span class="token punctuation">,</span> value<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        model<span class="token punctuation">.</span>value <span class="token operator">=</span> <span class="token punctuation">{</span> <span class="token operator">...</span>obj<span class="token punctuation">,</span> <span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token operator">:</span> value <span class="token punctuation">}</span>\n        <span class="token keyword">return</span> <span class="token boolean">true</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token function">set</span> <span class="token punctuation">(</span>newValue<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">,</span> newValue<span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre></div><p>With this version we can assign <code>model.value = something</code> or <code>model.value.firstName = something</code> and in either case it will be magically converted into an event. That allows for both <code>v-model=&quot;model&quot;</code> and <code>v-model=&quot;model.firstName&quot;</code>, whichever one we need.</p>',6),x='{"title":"Computed with v-model","description":"","frontmatter":{},"headers":[{"level":2,"title":"Libraries","slug":"libraries"},{"level":2,"title":"Alternatives","slug":"alternatives"},{"level":2,"title":"Advanced usage - proxying objects","slug":"advanced-usage-proxying-objects"}],"relativePath":"patterns/computed-v-model.md","lastUpdated":1633057808723}',_={};const T=Object.assign(_,{setup:function(n){return(n,a)=>{const s=f("live-example");return l(),u("div",null,[q,g(s,null,{default:w((()=>[g(V)])),_:1}),j])}}});export{x as __pageData,T as default};
